unitsize(1 cm);

pair A, B, M, O, R, S;

O = (0,0);
A = (5,0);
R = (4,3);
B = (-2,3);
S = (1/5,-18/5);
M = (A + R)/2;

draw((-3,-1)--(5,5/3),red + dashed);
draw(O--M,red,Arrow(6));
draw((-4,0)--(6,0));
draw((0,-4)--(0,4));
draw(O--A,Arrow(6));
draw(O--R,Arrow(6));
draw(A--R,dashed,Arrow(6));
draw(O--B,Arrow(6));
draw(O--S,Arrow(6));
draw(B--S,dashed,Arrow(6));
label("$\begin{pmatrix} 5 \\ 0 \end{pmatrix}$", A, S);
